sql:
SELECT user_id, SUM(price) AS TotalPurchaseAmount
FROM user_purchases
GROUP BY user_id;

SELECT COUNT(*) AS total_tracks
FROM (
    SELECT track_id FROM user_favorites WHERE user_id = 1
    UNION
    SELECT track_id FROM user_obsessions WHERE user_id = 1
) AS favorite_or_obsessed_tracks;

SELECT track_name 
FROM tracks 
WHERE track_id NOT IN (
    SELECT track_id 
    FROM user_favorites
);

SELECT track_name, love_count, purchase_count
FROM tracks
WHERE love_count > 20 AND purchase_count > 50;

SELECT COUNT(track_id) 
FROM user_purchases 
WHERE user_id = 0;

SELECT artist_id, followers_count AS average_followers
FROM artists
WHERE followers_count > (
  SELECT AVG(followers_count) FROM artists
);
